FROM jsonb_array_elements('[{"id":"little-wishford-sp2","name":"Little Wishford","village":"Little Wishford","town":"Salisbury","county":"Wiltshire","postcode":"SP2","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.04576,"lng":-1.8408},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"littleton-so22","name":"Littleton","village":"Littleton","town":"Winchester","county":"Hampshire","postcode":"SO22","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Winchester","coords":{"lat":51.05788,"lng":-1.32468},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":{"avgDetached":920528,"avgSemi":593316,"avgTerraced":518049,"avgFlat":null,"asOf":"2026-05"},"councilTaxBand":"D","overview":"Littleton is a village in the joint civil parish of Littleton and Harestock (population 3,577 at the 2011 Census), three miles north-west of Winchester city centre on the downs between the B3420 (the old Roman road to Cirencester) and the B3049 Stockbridge road. Half a dozen of its houses date from the fifteenth and sixteenth centuries — some are Hampshire Hall houses — clustered around the medieval St Catherine''s church and the old parsonage. The bulk of the village dates from the early twentieth century, with a village hall built in 1920 as a memorial to residents killed in the First World War. Littleton holds around 450 homes and 2,800 electors across the joint parish (Harestock to the south-east is the newer settlement). It sits inside the Winchester gap zone and just outside the South Downs National Park to the south.","character":"Genuine ''open'' village with two centres: an older lane (Main Road and Andover Road) of brick-and-flint and 1920s–1930s cottages around St Catherine''s church and the village hall, plus a tighter ribbon of post-war and recent-build housing toward Harestock. Quiet but well-equipped, with extensive sports and recreational facilities.","amenities":["Running Horse Inn (Main Road, gastro pub with rooms)","St Catherine''s Church (Church of England)","Littleton Village Hall (1920, war memorial)","Littleton Recreation Ground, tennis, cricket and football","Annual Littleton and Harestock Show","Harestock garage and small shops on the southern end (1 mi)","Wyke Mark and Andover Road local convenience shops","Sparsholt College Hampshire (3 mi) — land-based further education","Full Winchester high street, Cathedral and Sainsbury''s (3 mi)"],"schools":[{"name":"Harestock Primary School","phase":"Primary","type":"State (Community)","ofsted":"Good (2023)","distance":"0.9 mi","url":"https://reports.ofsted.gov.uk/provider/21/116241"},{"name":"Henry Beaufort School","phase":"Secondary","type":"State (Comprehensive)","ofsted":"Good (2023)","distance":"1.1 mi","url":"https://reports.ofsted.gov.uk/provider/21/116438"},{"name":"Peter Symonds College (16-18)","phase":"Sixth Form","type":"State (Sixth-form college)","ofsted":"Outstanding (2019)","distance":"2.5 mi","url":"https://reports.ofsted.gov.uk/provider/22/130688"}],"transport":{"commutes":[{"to":"London Waterloo","time":"56m (fastest) / 1h 23m (average)","mode":"drive to Winchester + direct train (SWR)","source":"https://www.thetrainline.com/train-times/winchester-to-london-waterloo"},{"to":"Southampton Central","time":"15m","mode":"train from Winchester (SWR)","source":"https://www.thetrainline.com/train-times/winchester-to-southampton-central"},{"to":"Basingstoke","time":"~25m","mode":"drive (M3)","source":"https://www.google.com/maps"}],"nearestStation":"Winchester (3.0 mi)","roads":"B3420 (Roman road, parish edge); B3049 (Stockbridge Road, parish edge); A34/M3 J9 ~3 mi"},"prices":{"avgSold12Mo":640807,"avgDetached":920528,"avgSemi":593316,"avgTerraced":518049,"avgBungalow":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/so22.html","asOf":"2026-05"},"thingsToDo":["Littleton and Harestock Show (September)","Walking on the Roman road (B3420) and around Crab Wood SSSI","Farley Mount Country Park (3 mi)","Hillier Garden Centre, Sir Harold Hillier Gardens (8 mi)","Sparsholt College open days and equestrian centre","Winchester Cathedral and the city Christmas market (3 mi)"],"placesToEat":[{"name":"The Running Horse Inn","type":"Gastropub with rooms","notes":"Village pub on Main Road; lunch, dinner and rooms","url":"https://www.runninghorseinn.co.uk/"},{"name":"Café Monde, Harestock","type":"Independent café","notes":"Local café at the Harestock end of the parish","url":"https://www.facebook.com/cafemondeharestock/"}],"pros":["Good Ofsted primary and Good catchment secondary (Henry Beaufort) inside the parish","Three miles from Winchester station and the direct Waterloo line","Mix of older brick-and-flint and inter-war housing; not pure estate","Active village life — show, hall, recreation ground, multiple groups","Outstanding sixth-form (Peter Symonds) is one bus or a short drive away"],"cons":["SO22 detached stock averages £920k — well above budget; terraced stock pushes £500k","B3420 and B3049 are busy commuter routes at peak","No mainline station within the village — Winchester drive or bus needed","Recent new-build pressure on the Harestock side has shaped local feeling","Some streets feel suburban rather than rural"],"whoItSuits":"Strong fit for a solo first-time buyer who wants Winchester convenience without buying inside the city — Henry Beaufort and Harestock primary are both Good and inside walking distance, and you keep direct trains to Waterloo. Realistically, only terraces and the cheaper end of semis will come into the £400k budget here; everything detached is over £900k. For prettier-but-pricier look at Sparsholt or Crawley (SO21); for cheaper similar commute, South Wonston (SO21) or Sutton Scotney further up the A34.","broadbandMedianMbps":null,"nearestStation":"Winchester (3.0 mi)","primarySupermarket":"Sainsbury''s, Middle Brook Street, Winchester (3.0 mi); Waitrose, Stockbridge Road, Winchester (2.5 mi)","images":[],"sources":[{"title":"Wikipedia — Littleton and Harestock","url":"https://en.wikipedia.org/wiki/Littleton_and_Harestock"},{"title":"Littleton and Harestock Parish Council","url":"https://lhpc.org.uk/about-2/"},{"title":"Ofsted — Harestock Primary School","url":"https://reports.ofsted.gov.uk/provider/21/116241"},{"title":"Ofsted — Henry Beaufort School","url":"https://reports.ofsted.gov.uk/provider/21/116438"},{"title":"Rightmove — SO22 house prices","url":"https://www.rightmove.co.uk/house-prices/so22.html"},{"title":"Trainline — Winchester to London Waterloo","url":"https://www.thetrainline.com/train-times/winchester-to-london-waterloo"}]},{"id":"lockerley-so51","name":"Lockerley","village":"Lockerley","town":"Romsey","county":"Hampshire","postcode":"SO51","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Romsey","coords":{"lat":50.99864,"lng":-1.507},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"longstock-so20","name":"Longstock","village":"Longstock","town":"Andover","county":"Hampshire","postcode":"SO20","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Andover","coords":{"lat":51.10068,"lng":-1.50248},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":"D","overview":"Longstock is a thatched-cottage village of around 500 residents on the west bank of the upper River Test, about two miles north of Stockbridge in the Test Valley district. Almost every house on the village street is timber-framed and thatched, with the prominent exception of the Peat Spade Inn — a Victorian gastropub-with-rooms that is now the village''s main commercial anchor. The parish church of St Mary''s was largely rebuilt in the 1880s, but the village''s older fabric is exceptional: Longstock is one of the most visually consistent surviving 17th- and 18th-century chalk-stream villages in southern England, which is partly why John Spedan Lewis bought the Longstock Park estate and made his family home there from 1945. Longstock Park (and the neighbouring Leckford Estate) remains owned by the John Lewis Partnership, with Longstock House used by Partnership senior management and Longstock Park Water Gardens open to the public on selected Sundays April–September.","character":"Pure thatched chalk-stream village: timber-frame, lime-render, thatch-and-deep-eaves cottages strung along Longstock Road and Cottage Lane. Tight conservation area; planning constraints are exceptionally strict. Building stock predominantly 17th–18th century with Victorian estate cottages.","amenities":["The Peat Spade Inn (gastropub with rooms)","St Mary''s Parish Church (1880s rebuild)","Village hall","Longstock Park Water Gardens (April–September)","Longstock Park Nursery (within parish)","Cricket club","Direct riverside access to upper Test beats","Within South Wessex Downs Special Landscape Area"],"schools":[{"name":"Stockbridge Primary School","phase":"Primary","ofsted":null,"distance":"2.0 mi","url":"https://reports.ofsted.gov.uk/"},{"name":"Test Valley School / Danebury School, Stockbridge","phase":"Secondary","ofsted":"Inadequate (2022)","distance":"2.5 mi","url":"https://reports.ofsted.gov.uk/"}],"transport":{"commutes":[{"to":"London Waterloo","time":"1h 10m","mode":"drive + direct train","source":"https://www.thetrainline.com/train-times/andover-to-london-waterloo"},{"to":"London Waterloo (fastest)","time":"1h 2m","mode":"drive + train","source":"https://www.thetrainline.com/train-times/andover-to-london-waterloo"}],"nearestStation":"Andover (5.0 mi)","roads":"A3057 (through village); A30 ~2 mi; A303 ~5 mi; M3 J8 ~14 mi"},"prices":{"avgSold12Mo":null,"avgDetached":null,"avgSemi":null,"avgTerraced":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/so20.html","asOf":"2026-05"},"thingsToDo":["Longstock Park Water Gardens (Partnership-owned, public Sundays)","Test Way long-distance footpath","Trout/grayling fishing on the upper Test","Walking the Stockbridge–Leckford–Longstock loop","Houghton Down chalk grassland (4 mi)","Mottisfont (National Trust) ~6 mi","Danebury Hill Fort (5 mi)"],"placesToEat":[{"name":"The Peat Spade Inn","type":"Gastropub with rooms","notes":"Mains around £19–£29; locally-cited destination dining","url":"https://www.peatspadeinn.co.uk/"}],"pros":["Outstanding visual character — one of England''s best surviving thatched chalk-stream villages","Direct access to upper Test fishing beats","Andover station 5 mi for direct Waterloo trains","Adjacent to Leckford Estate amenities (shop, café, water gardens)"],"cons":["Tight conservation regime restricts alterations and extensions","Single pub; no shop or post office in the village itself","Heritage-grade prices for thatched stock with high maintenance","Secondary catchment school rated Inadequate in 2022"],"whoItSuits":"Buyers willing to pay a heritage premium for a postcard thatched cottage in one of England''s most photographed chalk-stream villages, and to accept the maintenance cycle that comes with thatch (re-thatching roughly every 25–35 years). Particularly suited to anglers, second-homers, downsizers and cash buyers. The village''s status as ''mostly Partnership-owned'' beyond its private street means open-market stock comes up less frequently than the village size suggests. Poor fit for first-time buyers and anyone needing a daily train commute without a car.","broadbandMedianMbps":null,"nearestStation":"Andover (5.0 mi)","primarySupermarket":"Waitrose, Stockbridge (2.5 mi); Sainsbury''s, Andover (5.5 mi)","images":[],"sources":["https://en.wikipedia.org/wiki/Longstock","https://leckfordestate.co.uk/","https://jlpmemorystore.org.uk/content/being_a_partner/leisure/residential_clubs/leckford_abbas/leckford","https://www.peatspadeinn.co.uk/","https://www.thetrainline.com/train-times/andover-to-london-waterloo","https://www.testvalley.gov.uk/benefitsandcounciltax/counciltax/council-tax-charges"]},{"id":"lover-sp5","name":"Lover","village":"Lover","town":"Salisbury","county":"Wiltshire","postcode":"SP5","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.00288,"lng":-1.87256},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"lower-bullington-so21","name":"Lower Bullington","village":"Lower Bullington","town":"Winchester","county":"Hampshire","postcode":"SO21","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Winchester","coords":{"lat":51.08288,"lng":-1.29756},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":{"avgDetached":1058605,"avgSemi":541803,"avgTerraced":488613,"avgFlat":null,"asOf":"2026-05"},"councilTaxBand":null,"overview":"Lower Bullington is a tiny hamlet in the Bullington civil parish of Test Valley borough, set in the chalk-stream valley of the River Dever about nine miles south-east of Andover and three miles east of the village of Sutton Scotney. The civil parish — comprising Upper Bullington and Lower Bullington — had a recorded population of just 101 at the 2001 Census. Lower Bullington sits in the valley bottom at around 60 m, while Upper Bullington runs along the parallel ridge to the north; both are off the A30 and reached by a single lane signed from Bullington Cross. The hamlet has no shop, school, pub or church of its own and shares amenities with the larger village of Barton Stacey, two miles west.","character":"Sparsely settled chalk-stream hamlet: a handful of brick-and-flint cottages, a working farm and one or two larger detached properties strung along Lower Bullington Lane. Inside the Test Valley Special Landscape Area, with the Dever cress beds prominent in the landscape. No through traffic and big skies; nearest streetlight is at Sutton Scotney.","amenities":["Nearest shop and pub: Barton Stacey village (The Swan Inn, Village Stores) — 2 mi","Nearest GP and pharmacy: Sutton Scotney (3 mi)","A303 service area and Co-op, Bullington Cross (1 mi)","Andover full retail and Sainsbury''s (9 mi)","Winchester full retail (8 mi)"],"schools":[{"name":"Barton Stacey Church of England Primary School","phase":"Primary","type":"State (Voluntary Controlled)","ofsted":"Good (2024)","distance":"2.4 mi","url":"https://reports.ofsted.gov.uk/provider/21/115898"},{"name":"Wonston Primary School","phase":"Primary","type":"State (Community)","ofsted":"Good (2023)","distance":"3.1 mi","url":"https://reports.ofsted.gov.uk/provider/21/115950"},{"name":"Test Valley School (Stockbridge)","phase":"Secondary","type":"State (Comprehensive)","ofsted":"Good (2022)","distance":"8.0 mi","url":"https://reports.ofsted.gov.uk/provider/21/116440"}],"transport":{"commutes":[{"to":"London Waterloo","time":"1h 13m","mode":"drive to Micheldever Station (4 mi) + direct train (SWR)","source":"https://www.thetrainline.com/stations/micheldever"},{"to":"Winchester (by road)","time":"~20m","mode":"drive (A34/A30)","source":"https://www.google.com/maps"},{"to":"Andover (by road)","time":"~15m","mode":"drive (A303)","source":"https://www.google.com/maps"}],"nearestStation":"Micheldever (4.2 mi)","roads":"A30 (parish edge); A34 ~1 mi; A303 (Bullington Cross) ~1 mi; M3 J9 ~9 mi"},"prices":{"avgSold12Mo":712724,"avgDetached":1058605,"avgSemi":541803,"avgTerraced":488613,"avgBungalow":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/so21.html","asOf":"2026-05"},"thingsToDo":["Walking the River Dever and the Test Way footpath","Tidbury Ring Iron Age hillfort (2 mi)","Bombay Sapphire Distillery, Laverstoke Mill (8 mi)","The Hawk Conservancy Trust, Andover (8 mi)","Whitchurch Silk Mill (10 mi)"],"placesToEat":[{"name":"The Swan Inn, Barton Stacey","type":"Village pub","notes":"Two miles west; the local for Bullington residents","url":"https://www.theswaninn-bartonstacey.co.uk/"},{"name":"Bullington Cross Inn","type":"Roadside pub","notes":"1 mile north at the A303/A34 junction","url":"https://whatpub.com/pubs/HAS/00059/bullington-cross-inn"}],"pros":["Three trunk roads (A30/A34/A303) within a mile; fast access to Andover, Winchester, the Midlands","Direct Waterloo trains from Micheldever, 4 miles south","Genuine downland silence at home; chalk-stream walks from the door","Two Good village primaries within 3 miles (Barton Stacey, Wonston)"],"cons":["Nothing in the hamlet itself — pub, shop, school all 2+ miles away","A303/A34 noise audible at Upper Bullington and the northern edge","Catchment secondary (Test Valley, Stockbridge) is 8 miles by road","SO21 detached stock averages £1.06m; tiny housing market means little ever lists here","Mobile signal and broadband patchy at the lower-valley end"],"whoItSuits":"Best understood as a quiet country bolt-hole for someone working from home with occasional London or Andover days. For a solo first-time buyer at £400k it''s effectively out of reach as a standalone freehold purchase — the few cottages that do come up are typically well above. Barton Stacey (2 mi west) has more terraced and semi stock at more attainable prices with the same A303 access; Wonston (3 mi south) is cheaper still with its own Good primary; Sutton Scotney (3 mi west) has the most amenities for the money.","broadbandMedianMbps":null,"nearestStation":"Micheldever (4.2 mi)","primarySupermarket":"Co-op, Bullington Cross (1.0 mi); Sainsbury''s, Andover Road, Andover (9.0 mi)","images":[],"sources":[{"title":"Wikipedia — Bullington, Hampshire","url":"https://en.wikipedia.org/wiki/Bullington,_Hampshire"},{"title":"Barton Stacey Parish Council — About","url":"https://www.bartonstaceyparishcouncil.gov.uk/about/"},{"title":"Ofsted — Barton Stacey CofE Primary","url":"https://reports.ofsted.gov.uk/provider/21/115898"},{"title":"Rightmove — SO21 house prices","url":"https://www.rightmove.co.uk/house-prices/so21.html"},{"title":"Trainline — Micheldever station","url":"https://www.thetrainline.com/stations/micheldever"}]},{"id":"lower-chicksgrove-sp3","name":"Lower Chicksgrove","village":"Lower Chicksgrove","town":"Salisbury","county":"Wiltshire","postcode":"SP3","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.064,"lng":-1.95668},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"lyndhurst-so43","name":"Lyndhurst","village":"Lyndhurst","town":"Southampton","county":"Hampshire","postcode":"SO43","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Southampton","coords":{"lat":50.86092,"lng":-1.58872},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"mead-end-sp5","name":"Mead End","village":"Mead End","town":"Salisbury","county":"Wiltshire","postcode":"SP5","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.00032,"lng":-1.87952},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"medstead-gu34","name":"Medstead","village":"Medstead","town":"Alton","county":"Hampshire","postcode":"GU34","hubCity":"Guildford","regionDir":"","settlementType":"","subRegion":"Alton","coords":{"lat":51.15116,"lng":-0.98648},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":{"avgDetached":694500,"avgSemi":null,"avgTerraced":null,"avgFlat":null,"asOf":"2025"},"councilTaxBand":"D","overview":"Medstead is a village and civil parish of around 2,000 residents in the East Hampshire district, four and a quarter miles south-west of Alton on a chalk plateau between the Itchen and Meon valleys. The parish reaches over 210 m at King''s Hill, making Medstead one of the highest villages in Hampshire; the 12th-century St Andrew''s Church and a Victorian wheelhouse with a working donkey wheel are among its six Grade II-listed buildings. Modern Medstead is anchored by the High Street, where the Castle of Comfort pub, the Handy Stores grocer-newsagent and Medstead Hardware (which houses the village sub-post office) sit close to St Andrew''s; the village hall, green and Medstead Primary lie at the other end. Medstead shares the heritage Watercress Line station with Four Marks, but commuters use Alton (4.3 mi) for direct Waterloo services. The parish was one of the first in the UK to receive broadband and now has Superfast FTTC available throughout.","character":"Largely unspoilt rural Hampshire village, more visually coherent than neighbouring Four Marks — period brick and weatherboarded cottages along the High Street, a working farmstead at South Town, and 1960s-1980s additions on the south and east edges. Council Tax Band D charge for Medstead in 2026/27 is around £2,310 (East Hampshire LA, 2026-27 schedule).","amenities":["Castle of Comfort (traditional freehouse, High Street)","Handy Stores (grocer + newsagent)","Medstead Hardware + sub-Post Office","St Andrew''s Church (12th century)","Medstead Village Hall and green","Convent of St Lucy","Tennis club and bowls club","Medstead Church of England Primary School (Good, Ofsted March 2023)","Medstead and Four Marks station (Watercress Line, heritage)"],"schools":[{"name":"Medstead Church of England Primary School","phase":"Primary","ofsted":"Good","distance":"0.3 mi","url":"https://reports.ofsted.gov.uk/provider/21/116300"},{"name":"Four Marks Church of England Primary School","phase":"Primary","ofsted":null,"distance":"1.8 mi","url":"https://reports.ofsted.gov.uk/"},{"name":"Amery Hill School, Alton","phase":"Secondary","ofsted":null,"distance":"4.3 mi","url":"https://reports.ofsted.gov.uk/"}],"transport":{"commutes":[{"to":"London Waterloo","time":"1h 13m","mode":"drive to Alton + direct train (South Western Railway)","source":"https://www.thetrainline.com/stations/alton"},{"to":"London Waterloo (fastest)","time":"1h 6m","mode":"drive + train","source":"https://www.thetrainline.com/train-times/alton-to-london-waterloo"},{"to":"Winchester (by road)","time":"~25m","mode":"drive (A31 via Four Marks)","source":"https://www.nationalrail.co.uk/"}],"nearestStation":"Alton (4.3 mi)","roads":"A31 ~1.5 mi (via Four Marks); A32 ~4 mi; M3 J9 ~14 mi"},"prices":{"avgSold12Mo":534986,"avgDetached":694500,"avgSemi":null,"avgTerraced":null,"avgFlat":null,"source":"https://www.getthedata.com/postcode/GU34-5PF","asOf":"2025"},"thingsToDo":["Walking King''s Hill (one of Hampshire''s highest points)","Watercress Line steam-train day trip (Alresford–Alton)","Annual village fête (July, on the green)","St Andrew''s Church and donkey-wheel wheelhouse heritage tour","Hattingley Valley Wines (~2 mi)","Triple fff Brewery taproom, Four Marks (~2 mi)","Jane Austen''s House Museum, Chawton (3 mi)"],"placesToEat":[{"name":"The Castle of Comfort","type":"Traditional pub","notes":"Freehouse on the High Street; pub lunches, range of bitters and real ales","url":"https://www.castleofcomfort.co.uk/"},{"name":"The Three Horseshoes, Bighton","type":"Country pub","notes":"Freehouse 3 mi west, near Alresford","url":"https://www.useyourlocal.com/pubs-in-medstead/"}],"pros":["Full village amenity set retained (pub, shop, post office, school)","Ofsted Good primary in the village (Medstead C of E)","Six Grade II-listed buildings and a 12th-century church","Substantial period stock alongside post-war additions"],"cons":["No commuter station — heritage line only, drive to Alton for Waterloo","Elevated chalk-ridge position can be exposed in winter","Limited choice of pubs; one in village","A31 traffic accumulates at the Four Marks pinch point at peak times"],"whoItSuits":"Families and couples wanting a working chalk-ridge village with a Good primary on the doorstep, a working post office and a traditional freehouse — all within four miles of Alton''s full retail set. The visual coherence of the High Street and the listed-building density distinguish it from neighbouring Four Marks. Best fit for buyers comfortable with a fifteen-minute drive to a mainline station, families with primary-age children, and downsizers from busier south-east towns. Less suitable for buyers needing daily train commutes without a car, or for those wanting the chocolate-box thatch character of the Test Valley villages further west.","broadbandMedianMbps":56,"nearestStation":"Alton (4.3 mi)","primarySupermarket":"Sainsbury''s, Draymans Way, Alton (4.5 mi); Handy Stores in village","images":[],"sources":["https://en.wikipedia.org/wiki/Medstead","https://www.medsteadpc.org/_VirDir/CoreContents/Organisations/Display.aspx?id=5676","https://www.medsteadpc.org/Local_Information_33013.aspx","https://reports.ofsted.gov.uk/provider/21/116300","https://www.medstead.hants.sch.uk/","https://www.easthants.gov.uk/sites/default/files/2026-03/Council%20tax%20per%20valuation%20band%202026-27.pdf","https://www.thetrainline.com/stations/alton","https://www.getthedata.com/postcode/GU34-5PF","https://littleplaceinthecountry.com/en/medstead-local-guide"]}]'::jsonb) AS value;

COMMIT;
